mapper.select:
SELECT id, processmodel_id AS processmodelId, interface_name AS interfaceName, is_default AS isDefault, created_at AS createdAt, updated_at AS updatedAt, interface_summary AS interfaceSummary FROM model_interface
AND id = #{id}
AND processmodel_id = #{processmodelId}
AND interface_name LIKE CONCAT('%', #{interfaceName}, '%')
ORDER BY created_at DESC
